/// <summary>
/// Creates the <c>BOSSalesLineForPicking</c> view.
/// </summary>
protected boolean createViews()
{
    return this.dropView(viewName) && this.executeSqlStatementWithParameters(this.createViewSqlStmt(),SqlParams::create());
}

public static void main(Args args)
{
    var builder = DBMSQLMonActiveQueriesViewBuilder::construct();
    builder.createSqlObjects();
}

/// </remarks>
private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();

    return sqlStmt;
}

private str as(str _fieldName, str _alias)
{
    return _fieldName + ' AS ' + _alias;
}

